mapper.insert:
INSERT INTO dish (
    name, category_id, price, image, description, status,
    create_time, update_time, create_user, update_user
) VALUES (
             #{name}, #{categoryId}, #{price}, #{image}, #{description}, #{status},
             NOW(), NOW(), #{createUser}, #{updateUser}
         )

mapper.select:
select d.*,c.name as categoryName from dish d left join category c on d.category_id=c.id


        and d.category_id=#{categoryId}


        and d.name like concat('%',#{name},'%')


        and d.status=#{status}


order by d.update_time desc
